export function useBaseApiRequest(): UseMutationResult<
  { data?: unknown },
  Error,
  { integrationId: string; connectionId: string; method: string; parameters: unknown }
> {
  return useMutation({
    mutationFn: async ({ integrationId, connectionId, method, parameters }) => {
