export function useAllegroApiRequest(): UseMutationResult<
  { status: number; statusText: string; data?: unknown; refreshed?: boolean },
  Error,
  { integrationId: string; connectionId: string; method: string; path: string; body?: unknown }
> {
  return useMutation({
