"use client";

import { useToast, Button, SectionHeader, SectionPanel } from "@/shared/ui";
import {
  useEffect,
  useState,
} from "react";

import {
  settingSections,
} from "./ProductSettingsConstants"; // TODO: This is a bit awkward, maybe move constants to feature too
import {
  PriceGroup,
  Catalog,
} from "@/features/products/types";
import type { CurrencyOption, CountryOption, Language } from "@/shared/types/internationalization";

import { PriceGroupsSettings } from "@/features/products/components/settings/pricing/PriceGroupsSettings";
import { CatalogsSettings } from "@/features/products/components/settings/catalogs/CatalogsSettings";
import { CategoriesSettings } from "@/features/products/components/settings/CategoriesSettings";
import { TagsSettings } from "@/features/products/components/settings/TagsSettings";
import { InternationalizationSettings } from "@/features/internationalization";
import { AiDescriptionSettings } from "@/features/products/components/settings/ai/AiDescriptionSettings";
import { AiTranslationSettings } from "@/features/products/components/settings/ai/AiTranslationSettings";

// New Modals
import { CatalogModal } from "@/features/products/components/settings/modals/CatalogModal";
import { LanguageModal } from "@/features/products/components/settings/modals/LanguageModal";
import { PriceGroupModal } from "@/features/products/components/settings/modals/PriceGroupModal";
import { CurrencyModal } from "@/features/products/components/settings/modals/CurrencyModal";
import { CountryModal } from "@/features/products/components/settings/modals/CountryModal";

import { 
  usePriceGroups, 
  useCatalogs, 
  useCategories, 
  useTags,
  useUpdatePriceGroupMutation,
  useDeletePriceGroupMutation,
  useDeleteCatalogMutation
} from "@/features/products/hooks/useProductSettingsQueries";
import {
  useCurrencies,
  useCountries,
  useLanguages,
  useDeleteCurrencyMutation,
  useDeleteCountryMutation,
  useDeleteLanguageMutation
} from "@/features/internationalization/hooks/useInternationalizationQueries";


export function ProductSettingsPage(): React.JSX.Element {
  const [activeSection, setActiveSection] =
    useState<(typeof settingSections)[number]>("Categories");

  // Modal State
  const [showCatalogModal, setShowCatalogModal] = useState(false);
  const [editingCatalog, setEditingCatalog] = useState<Catalog | null>(null);
  const [showLanguageModal, setShowLanguageModal] = useState(false);
  const [editingLanguage, setEditingLanguage] = useState<Language | null>(null);
  const [showPriceGroupModal, setShowPriceGroupModal] = useState(false);
  const [editingPriceGroup, setEditingPriceGroup] = useState<PriceGroup | null>(null);
  const [showCurrencyModal, setShowCurrencyModal] = useState(false);
  const [editingCurrency, setEditingCurrency] = useState<CurrencyOption | null>(null);
  const [showCountryModal, setShowCountryModal] = useState(false);
  const [editingCountry, setEditingCountry] = useState<CountryOption | null>(null);

  const { toast } = useToast();

  // Queries
  const { data: priceGroups = [], isLoading: loadingGroups } = usePriceGroups();
  const { data: catalogs = [], isLoading: loadingCatalogs } = useCatalogs();
  const { data: currencies = [], isLoading: loadingCurrencies } = useCurrencies();
  const { data: countries = [], isLoading: loadingCountries } = useCountries();
  const { data: languages = [], isLoading: languagesLoading, error: languagesError } = useLanguages();

  const [selectedCategoryCatalogId, setSelectedCategoryCatalogId] = useState<string | null>(null);
  const [selectedTagCatalogId, setSelectedTagCatalogId] = useState<string | null>(null);

  const { data: productCategories = [], isLoading: loadingCategories, refetch: refetchCategories } = useCategories(selectedCategoryCatalogId);
  const { data: productTags = [], isLoading: loadingTags, refetch: refetchTags } = useTags(selectedTagCatalogId);

  // Mutations
  const updatePriceGroupMutation = useUpdatePriceGroupMutation();
  const deletePriceGroupMutation = useDeletePriceGroupMutation();
  const deleteCatalogMutation = useDeleteCatalogMutation();
  const deleteCurrencyMutation = useDeleteCurrencyMutation();
  const deleteCountryMutation = useDeleteCountryMutation();
  const deleteLanguageMutation = useDeleteLanguageMutation();

  const defaultGroupId = priceGroups.find((g: import("@/features/products/types").PriceGroup) => g.isDefault)?.id ?? "";

  useEffect(() => {
    if (catalogs.length > 0) {
      if (!selectedCategoryCatalogId) {
        const def = catalogs.find((c: Catalog) => c.isDefault) || catalogs[0];
        if (def) setSelectedCategoryCatalogId(def.id);
      }
      if (!selectedTagCatalogId) {
        const def = catalogs.find((c: Catalog) => c.isDefault) || catalogs[0];
        if (def) setSelectedTagCatalogId(def.id);
      }
    }
  }, [catalogs, selectedCategoryCatalogId, selectedTagCatalogId]);

  const handleSetDefaultGroup = async (groupId: string): Promise<void> => {
    const group = priceGroups.find((g: PriceGroup) => g.id === groupId);
    if (!group) return;
    try {
      await updatePriceGroupMutation.mutateAsync({ ...group, isDefault: true });
      toast("Default price group updated.", { variant: "success" });
    } catch (error) {
      console.error(error);
    }
  };

  const handleDeleteCatalog = async (catalog: Catalog): Promise<void> => {
    if (!confirm(`Delete catalog "${catalog.name}"?`)) return;
    try {
      await deleteCatalogMutation.mutateAsync(catalog.id);
    } catch (err) { console.error(err); }
  };

  const handleDeleteGroup = async (group: PriceGroup): Promise<void> => {
    if (priceGroups.length <= 1) {
      toast("At least one price group is required.", { variant: "error" });
      return;
    }
    if (!confirm(`Delete price group "${group.name}"?`)) return;
    try {
      await deletePriceGroupMutation.mutateAsync(group.id);
    } catch (err) { console.error(err); }
  };

  return (
    <SectionPanel className="p-6">
      <SectionHeader
        title="Product Settings"
        className="mb-6"
      />
      <div className="grid gap-6 md:grid-cols-[240px_1fr]">
        <SectionPanel className="p-4">
          <div className="flex flex-col gap-2">
            {settingSections.map((section: typeof settingSections[number]) => (
              <Button
                key={section}
                onClick={() => setActiveSection(section)}
                className={`justify-start rounded px-3 py-2 text-left text-sm transition ${
                  activeSection === section
                    ? "bg-gray-800 text-white"
                    : "text-gray-300 hover:bg-muted/50/60"
                }`}
              >
                {section}
              </Button>
            ))}
          </div>
        </SectionPanel>
        <SectionPanel className="p-6">
          {activeSection === "Categories" && (
            <CategoriesSettings
              loading={loadingCategories}
              categories={productCategories}
              catalogs={catalogs}
              selectedCatalogId={selectedCategoryCatalogId}
              onCatalogChange={(id: string | null): void => { setSelectedCategoryCatalogId(id); }}
              onRefresh={() => void refetchCategories()}
            />
          )}
          {activeSection === "Tags" && (
            <TagsSettings
              loading={loadingTags}
              tags={productTags}
              catalogs={catalogs}
              selectedCatalogId={selectedTagCatalogId}
              onCatalogChange={(id: string | null): void => { setSelectedTagCatalogId(id); }}
              onRefresh={() => void refetchTags()}
            />
          )}
          {activeSection === "Price Groups" && (
            <PriceGroupsSettings
              loadingGroups={loadingGroups}
              priceGroups={priceGroups}
              defaultGroupId={defaultGroupId}
              onDefaultGroupChange={(id: string): void => { void handleSetDefaultGroup(id); }}
              defaultGroupSaving={updatePriceGroupMutation.isPending}
              handleOpenCreate={(): void => { setEditingPriceGroup(null); setShowPriceGroupModal(true); }}
              handleEditGroup={(g: PriceGroup): void => { setEditingPriceGroup(g); setShowPriceGroupModal(true); }}
              handleDeleteGroup={(g: PriceGroup): void => { void handleDeleteGroup(g); }}
            />
          )}
          {activeSection === "Catalogs" && (
            <CatalogsSettings
              loadingCatalogs={loadingCatalogs}
              catalogs={catalogs}
              languages={languages}
              handleOpenCatalogModal={(): void => { setEditingCatalog(null); setShowCatalogModal(true); }}
              handleEditCatalog={(c: Catalog): void => { setEditingCatalog(c); setShowCatalogModal(true); }}
              handleDeleteCatalog={(c: Catalog): void => { void handleDeleteCatalog(c); }}
            />
          )}
          {activeSection === "Internationalization" && (
            <InternationalizationSettings
              loadingCurrencies={loadingCurrencies}
              currencyOptions={currencies}
              handleOpenCurrencyModal={(c: CurrencyOption | undefined): void => { setEditingCurrency(c ?? null); setShowCurrencyModal(true); }}
              handleDeleteCurrency={(c: CurrencyOption): void => { 
                void (async (): Promise<void> => {
                  if (confirm(`Delete ${c.code}?`)) {
                    await deleteCurrencyMutation.mutateAsync(c.id);
                  }
                })();
              }}
              loadingCountries={loadingCountries}
              filteredCountries={countries}
              countrySearch=""
              setCountrySearch={() => {}}
              handleOpenCountryModal={(c: CountryOption | undefined): void => { setEditingCountry(c ?? null); setShowCountryModal(true); }}
              handleDeleteCountry={(c: CountryOption): void => {
                void (async (): Promise<void> => {
                  if (confirm(`Delete ${c.name}?`)) {
                    await deleteCountryMutation.mutateAsync(c.id);
                  }
                })();
              }}
              languagesLoading={languagesLoading}
              languagesError={languagesError instanceof Error ? languagesError.message : (languagesError || null)}
              languages={languages}
              handleOpenNewLanguageModal={(): void => { setEditingLanguage(null); setShowLanguageModal(true); }}
              handleOpenLanguageModal={(l: Language): void => { setEditingLanguage(l); setShowLanguageModal(true); }}
              handleDeleteLanguage={(l: Language): void => {
                void (async (): Promise<void> => {
                  if (confirm(`Delete ${l.name}?`)) {
                    await deleteLanguageMutation.mutateAsync(l.id);
                  }
                })();
              }}
            />
          )}
          {activeSection === "AI Description" && <AiDescriptionSettings />}
          {activeSection === "AI Translation" && <AiTranslationSettings />}
        </SectionPanel>
      </div>

      {/* Modals */}
      <CatalogModal
        isOpen={showCatalogModal}
        onClose={() => setShowCatalogModal(false)}
        onSuccess={(): void => { setShowCatalogModal(false); }}
        catalog={editingCatalog}
        languages={languages}
        languagesLoading={languagesLoading}
        languagesError={languagesError instanceof Error ? languagesError.message : (languagesError || null)}
        priceGroups={priceGroups}
        loadingGroups={loadingGroups}
        defaultGroupId={defaultGroupId}
      />

      <LanguageModal
        isOpen={showLanguageModal}
        onClose={() => setShowLanguageModal(false)}
        onSuccess={(): void => { setShowLanguageModal(false); }}
        language={editingLanguage}
        countries={countries}
      />

      <PriceGroupModal
        isOpen={showPriceGroupModal}
        onClose={() => setShowPriceGroupModal(false)}
        onSuccess={(): void => { setShowPriceGroupModal(false); }}
        priceGroup={editingPriceGroup}
        currencyOptions={currencies}
        loadingCurrencies={loadingCurrencies}
        priceGroups={priceGroups}
      />

      <CurrencyModal
        isOpen={showCurrencyModal}
        onClose={() => setShowCurrencyModal(false)}
        onSuccess={(): void => { setShowCurrencyModal(false); }}
        currency={editingCurrency}
      />

      <CountryModal
        isOpen={showCountryModal}
        onClose={() => setShowCountryModal(false)}
        onSuccess={(): void => { setShowCountryModal(false); }}
        country={editingCountry}
        currencyOptions={currencies}
        loadingCurrencies={loadingCurrencies}
      />
    </SectionPanel>
  );
}

"use client";

import { useQuery, useMutation, useQueryClient, type UseQueryResult, type UseMutationResult } from "@tanstack/react-query";
import { fetchAssets3D, fetchCategories, fetchTags } from "@/features/viewer3d/api";
import type { Asset3DListFilters, Asset3DRecord } from "@/features/viewer3d/types";

export const asset3dKeys = {
  all: ["assets3d"] as const,
  list: (filters: Asset3DListFilters) => ["assets3d", "list", filters] as const,
  categories: ["assets3d", "categories"] as const,
  tags: ["assets3d", "tags"] as const,
  detail: (id: string | null) => ["assets3d", "detail", id] as const,
};

export function useAssets3D(filters: Asset3DListFilters): UseQueryResult<Asset3DRecord[], Error> {
  return useQuery({
    queryKey: asset3dKeys.list(filters),
    queryFn: () => fetchAssets3D(filters),
  });
}

export function useAsset3DCategories(): UseQueryResult<string[], Error> {
  return useQuery({
    queryKey: asset3dKeys.categories,
    queryFn: fetchCategories,
  });
}

export function useAsset3DTags(): UseQueryResult<string[], Error> {
  return useQuery({
    queryKey: asset3dKeys.tags,
    queryFn: fetchTags,
  });
}

export function useAsset3DById(id: string | null): UseQueryResult<Asset3DRecord, Error> {
  return useQuery<Asset3DRecord>({
    queryKey: asset3dKeys.detail(id),
    queryFn: async () => {
      const res = await fetch(`/api/assets3d/${id}`);
      if (!res.ok) {
        throw new Error("Failed to fetch 3D asset");
      }
      return (await res.json()) as Asset3DRecord;
    },
    enabled: Boolean(id),
  });
}

export function useDeleteAsset3DMutation(): UseMutationResult<void, Error, string> {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async (id: string) => {
      const res = await fetch(`/api/assets3d/${id}`, {
        method: "DELETE",
      });
      if (!res.ok) throw new Error("Failed to delete 3D asset");
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: asset3dKeys.all });
    },
  });
}

export function useUpdateAsset3DMutation(): UseMutationResult<Asset3DRecord, Error, { id: string; data: Partial<Asset3DRecord> }> {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async ({ id, data }) => {
      const res = await fetch(`/api/assets3d/${id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      });
      if (!res.ok) throw new Error("Failed to update 3D asset");
      return res.json();
    },
    onSuccess: (data) => {
      void queryClient.invalidateQueries({ queryKey: asset3dKeys.all });
      void queryClient.invalidateQueries({ queryKey: asset3dKeys.detail(data.id) });
    },
  });
}

import "server-only";

import { NextRequest, NextResponse } from "next/server";
import { randomUUID } from "crypto";
import { resolveError } from "@/shared/errors/resolve-error";
import { badRequestError } from "@/shared/errors/app-error";
import type { SystemLogLevel } from "@/shared/types/system-logs";
import type {
  ApiHandlerOptions,
  ApiHandlerContext,
  ApiRouteHandler,
  ApiRouteHandlerWithParams,
} from "@/shared/types/api";

// Local type definitions to avoid importing from features layer
type LogSystemEventParams = {
  level: SystemLogLevel;
  message: string;
  source: string;
  error?: unknown;
  request?: NextRequest;
  requestId?: string;
  statusCode?: number;
  context?: Record<string, unknown>;
};

type ErrorFingerprintParams = {
  message: string;
  source: string;
  request: NextRequest;
  statusCode: number;
  error: unknown;
};

// Stub implementations to avoid features layer dependency
const logSystemEvent = async (params: LogSystemEventParams): Promise<void> => {
  // Implementation would be injected or moved to shared layer
  console.log('System event:', params);
};

const getErrorFingerprint = (params: ErrorFingerprintParams): string => {
  // Simple fingerprint generation
  return `${params.source}-${params.statusCode}-${Date.now()}`;
};

export type {
  ApiHandlerOptions,
  ApiHandlerContext,
  ApiRouteHandler,
  ApiRouteHandlerWithParams,
};

/**
 * Wraps an API route handler with automatic error handling, logging, and request tracking.
 *
 * Features:
 * - Automatic error catching and standardized error responses
 * - Request ID generation and tracking
 * - Performance timing
 * - Structured logging for both errors and successes
 * - Consistent error response format
 *
 * @example
 * ```ts
 * export const GET = apiHandler(
 *   async (req, ctx) => {
 *     const data = await fetchData();
 *     return NextResponse.json(data);
 *   },
 *   { source: "products.GET" }
 * );
 * ```
 */
export function apiHandler(
  handler: ApiRouteHandler,
  options: ApiHandlerOptions
): (request: NextRequest) => Promise<Response> {
  return async (request: NextRequest) => {
    const requestId = request.headers.get("x-request-id") ?? randomUUID();
    const startTime = performance.now();

    const context: ApiHandlerContext = {
      requestId,
      startTime,
      getElapsedMs: (): number => Math.round(performance.now() - startTime),
    };

    try {
      const response = await handler(request, context);

      // Log successful requests if configured
      if (options.logSuccess) {
        void logSystemEvent({
          level: options.successLogLevel ?? "info",
          message: `${options.source} completed successfully`,
          source: options.source,
          request,
          requestId,
          statusCode: response.status,
          context: {
            durationMs: context.getElapsedMs(),
          },
        });
      }

      // Add request ID to response headers for client-side tracking
      if (!response.headers.has("x-request-id")) {
        response.headers.set("x-request-id", requestId);
      }
      return response;
    } catch (error) {
      return createErrorResponseWithTiming(error, request, context, options);
    }
  };
}

/**
 * Wraps an API route handler with params (for dynamic routes like [id]).
 *
 * @example
 * ```ts
 * export const GET = apiHandlerWithParams<{ id: string }>(
 *   async (req, ctx, params) => {
 *     const item = await getById(params.id);
 *     return NextResponse.json(item);
 *   },
 *   { source: "products/[id].GET" }
 * );
 * ```
 */
export function apiHandlerWithParams<P extends Record<string, string>>(
  handler: ApiRouteHandlerWithParams<P>,
  options: ApiHandlerOptions
): (
  request: NextRequest,
  context: { params: Promise<P> }
) => Promise<Response> {
  return async (request: NextRequest, routeContext: { params: Promise<P> }) => {
    const requestId = request.headers.get("x-request-id") ?? randomUUID();
    const startTime = performance.now();

    const handlerContext: ApiHandlerContext = {
      requestId,
      startTime,
      getElapsedMs: () => Math.round(performance.now() - startTime),
    };

    try {
      const params = await routeContext.params;
      const response = await handler(request, handlerContext, params);

      if (options.logSuccess) {
        void logSystemEvent({
          level: options.successLogLevel ?? "info",
          message: `${options.source} completed successfully`,
          source: options.source,
          request,
          requestId,
          statusCode: response.status,
          context: {
            durationMs: handlerContext.getElapsedMs(),
            params,
          },
        });
      }

      if (!response.headers.has("x-request-id")) {
        response.headers.set("x-request-id", requestId);
      }
      return response;
    } catch (error) {
      return createErrorResponseWithTiming(
        error,
        request,
        handlerContext,
        options
      );
    }
  };
}

/**
 * Creates an error response with timing information and logging.
 */
function createErrorResponseWithTiming(
  error: unknown,
  request: NextRequest,
  context: ApiHandlerContext,
  options: ApiHandlerOptions
): Response {
  const resolved = resolveError(error, {
    ...(options.fallbackMessage !== undefined && { fallbackMessage: options.fallbackMessage }),
  });

  const level: SystemLogLevel = resolved.expected ? "warn" : "error";
  const durationMs = context.getElapsedMs();

  // Log the error with full context
  void logSystemEvent({
    level,
    message: resolved.message,
    source: options.source,
    error,
    request,
    requestId: context.requestId,
    statusCode: resolved.httpStatus,
    context: {
      errorId: resolved.errorId,
      code: resolved.code,
      durationMs,
      ...(resolved.meta ? { meta: resolved.meta } : {}),
    },
  });

  // Build response payload
  const payload: Record<string, unknown> = {
    error: resolved.message,
    code: resolved.code,
    errorId: resolved.errorId,
  };

  const fingerprint = getErrorFingerprint({
    message: resolved.message,
    source: options.source,
    request,
    statusCode: resolved.httpStatus,
    error,
  });

  payload.fingerprint = fingerprint;

  if (resolved.retryable) {
    payload.retryable = true;
    if (resolved.retryAfterMs) {
      payload.retryAfterMs = resolved.retryAfterMs;
    }
  }

  if (resolved.expected && resolved.meta) {
    payload.details = resolved.meta;
  } else if (options.includeDetails && resolved.meta) {
    payload.details = resolved.meta;
  }

  const response = NextResponse.json(payload, { status: resolved.httpStatus });
  response.headers.set("x-request-id", context.requestId);
  response.headers.set("x-error-id", resolved.errorId);
  response.headers.set("x-error-fingerprint", fingerprint);

  if (resolved.retryable && resolved.retryAfterMs) {
    const retryAfterSeconds = Math.ceil(resolved.retryAfterMs / 1000);
    response.headers.set("Retry-After", String(retryAfterSeconds));
  }

  return response;
}

/**
 * Helper to extract common query parameters.
 */
export function getQueryParams(request: NextRequest): URLSearchParams {
  return new URL(request.url).searchParams;
}

/**
 * Helper to get a required query parameter, throws if missing.
 */
export function getRequiredParam(
  searchParams: URLSearchParams,
  name: string
): string {
  const value = searchParams.get(name);
  if (!value) {
    throw badRequestError(`Missing required parameter: ${name}`);
  }
  return value;
}

/**
 * Helper to parse pagination parameters.
 */
export function getPaginationParams(searchParams: URLSearchParams): {
  page: number;
  pageSize: number;
  skip: number;
} {
  const page = Math.max(1, parseInt(searchParams.get("page") ?? "1", 10));
  const pageSize = Math.min(
    100,
    Math.max(1, parseInt(searchParams.get("pageSize") ?? "20", 10))
  );
  const skip = (page - 1) * pageSize;
  return { page, pageSize, skip };
}

import "server-only";

import { NextResponse } from "next/server";
import { randomUUID } from "crypto";
import { resolveError } from "@/shared/errors/resolve-error";
import { validationError } from "@/shared/errors/app-error";

// Local type definitions to avoid importing from features layer
type LogSystemEventParams = {
  level: string;
  message: string;
  source: string;
  error?: unknown;
  request?: Request;
  requestId?: string;
  statusCode?: number;
  context?: Record<string, unknown>;
};

type ErrorFingerprintParams = {
  message: string;
  source: string;
  request?: Request;
  statusCode: number;
  error: unknown;
};

// Stub implementations to avoid features layer dependency
const logSystemEvent = async (params: LogSystemEventParams): Promise<void> => {
  // Implementation would be injected or moved to shared layer
  console.log('System event:', params);
};

const getErrorFingerprint = (params: ErrorFingerprintParams): string => {
  // Simple fingerprint generation
  return `${params.source}-${params.statusCode}-${Date.now()}`;
};

type ApiErrorOptions = {
  request?: Request | undefined;
  source?: string | undefined;
  fallbackMessage?: string | undefined;
  includeDetails?: boolean | undefined;
  extra?: Record<string, unknown> | undefined;
  /** Request ID for tracing (will be included in response headers) */
  requestId?: string | undefined;
};

/**
 * Creates a standardized error response with logging.
 *
 * Features:
 * - Resolves any error to a standardized format
 * - Logs to system log with appropriate level
 * - Includes retry information for retryable errors
 * - Sets appropriate headers (x-request-id, x-error-id, Retry-After)
 * - Differentiates between expected (user) and unexpected (server) errors
 */
export const createErrorResponse = (
  error: unknown,
  options?: ApiErrorOptions
): NextResponse => {
  const resolved = resolveError(error, {
    ...(options?.fallbackMessage ? { fallbackMessage: options.fallbackMessage } : {}),
  });

  const requestId =
    options?.requestId ??
    options?.request?.headers.get("x-request-id") ??
    randomUUID();

  const fingerprint = getErrorFingerprint({
    message: resolved.message,
    source: options?.source ?? "api",
    ...(options?.request ? { request: options.request } : {}),
    statusCode: resolved.httpStatus,
    error,
  });

  // Determine log level based on error type
  const level = resolved.critical ? "error" : resolved.expected ? "warn" : "error";

  // Log the error
  void logSystemEvent({
    level,
    message: resolved.message,
    source: options?.source ?? "api",
    error,
    ...(options?.request ? { request: options.request } : {}),
    requestId,
    statusCode: resolved.httpStatus,
    context: {
      errorId: resolved.errorId,
      code: resolved.code,
      critical: resolved.critical,
      retryable: resolved.retryable,
      ...(resolved.retryAfterMs ? { retryAfterMs: resolved.retryAfterMs } : {}),
      ...(resolved.meta ? { meta: resolved.meta } : {}),
    },
  });

  // Build response payload
  const payload: Record<string, unknown> = {
    error: resolved.message,
    code: resolved.code,
    errorId: resolved.errorId,
    fingerprint,
  };

  // Include retry information for retryable errors
  if (resolved.retryable) {
    payload.retryable = true;
    if (resolved.retryAfterMs) {
      payload.retryAfterMs = resolved.retryAfterMs;
    }
  }

  // Include details for expected errors or when explicitly requested
  if (resolved.expected && resolved.meta) {
    payload.details = resolved.meta;
  } else if (options?.includeDetails && resolved.meta) {
    payload.details = resolved.meta;
  }

  // Merge any extra payload fields
  if (options?.extra) {
    Object.assign(payload, options.extra);
  }

  // Create response
  const response = NextResponse.json(payload, { status: resolved.httpStatus });

  // Set tracking headers
  response.headers.set("x-request-id", requestId);
  response.headers.set("x-error-id", resolved.errorId);
  response.headers.set("x-error-fingerprint", fingerprint);

  // Set Retry-After header for retryable errors
  if (resolved.retryable && resolved.retryAfterMs) {
    // Convert to seconds for HTTP header
    const retryAfterSeconds = Math.ceil(resolved.retryAfterMs / 1000);
    response.headers.set("Retry-After", String(retryAfterSeconds));
  }

  return response;
};

/**
 * Creates a simple error response without logging.
 * Use sparingly - prefer createErrorResponse for proper tracing.
 */
export const createSimpleErrorResponse = (
  message: string,
  status: number,
  code?: string
): NextResponse => {
  return NextResponse.json(
    {
      error: message,
      code: code ?? "ERROR",
    },
    { status }
  );
};

/**
 * Creates a validation error response from field errors.
 */
export const createValidationErrorResponse = (
  fieldErrors: Record<string, string[]>,
  options?: Pick<ApiErrorOptions, "request" | "source" | "requestId">
): NextResponse => {
  const error = validationError("Validation failed", { fields: fieldErrors });
  return createErrorResponse(error, options);
};

